import { clsx, type ClassValue } from 'clsx';
import { transformMerge } from 'tailwind-merge';
export function cn(...inputs: ClassValue[]) {
  return clsx(inputs);
}

import * as React from 'react';
import { cn } from '../../lib/utils';
export const Button = React.forwardRef<HTMLButtonElement, any>((props, ref) => {
  return <button ref={ref} className={cn('px-4 py-2 bg-blue-500 rounded text-white', props.className)} {...props} />;
});

import * as React from 'react';
import { cn } from '../../lib/utils';
export function Dialog({ isOpen, children }: { isOpen: boolean, children: React.ReactNode }) {
  if (!isOpen) return null;
  return <div className={cn('fixed inset-0 z-50 bg-black/50 flex items-center justify-center')}>{children}</div>;
}

import * as React from 'react';
import { cn } from '../../lib/utils';
export function Avatar({ src, alt }: { src: string; alt?: string }) {
  return <img src={src} alt={alt} className={cn('h-10 w-10 rounded-full object-cover')} />;
}

export * from './components/ui/button';
export * from './components/ui/dialog';
export * from './components/ui/avatar';
export * from './lib/utils';
